import socket
import threading
import json
import math

class GameServer:
    def __init__(self, host='127.0.0.1', port=12345):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server.bind((host, port))
        self.clients = {}
        self.player_positions = {}
        self.running = True

    def start(self):
        print("Server started...")
        threading.Thread(target=self.listen_for_clients).start()
        threading.Thread(target=self.broadcast_game_state).start()

    def listen_for_clients(self):
        while self.running:
            data, addr = self.server.recvfrom(1024)
            if addr not in self.clients:
                self.clients[addr] = {}
            self.handle_client_message(data, addr)

    def handle_client_message(self, data, addr):
        message = json.loads(data.decode())
        if message['type'] == 'update_position':
            self.player_positions[addr] = message['position']
            self.send_full_game_state(addr)

    def send_full_game_state(self, addr):
        game_state = {
            'type': 'full_game_state',
            'positions': self.player_positions
        }
        self.server.sendto(json.dumps(game_state).encode(), addr)

    def broadcast_game_state(self):
        while self.running:
            for client in self.clients.keys():
                self.send_full_game_state(client)

    def stop(self):
        self.running = False
        self.server.close()

if __name__ == "__main__":
    game_server = GameServer()
    try:
        game_server.start()
    except KeyboardInterrupt:
        game_server.stop()